CREATE TABLE IF NOT EXISTS `instruments` (
	`id` int AUTO_INCREMENT NOT NULL,
	`name` varchar(100) NOT NULL,
	`category` varchar(100) NOT NULL,
	`icon` varchar(50),
	`color` varchar(20),
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `instruments_id` PRIMARY KEY(`id`)
);

CREATE TABLE IF NOT EXISTS `lessons` (
	`id` int AUTO_INCREMENT NOT NULL,
	`studentId` int NOT NULL,
	`title` varchar(255) NOT NULL,
	`description` text,
	`scheduledAt` timestamp NOT NULL,
	`duration` int NOT NULL DEFAULT 60,
	`status` enum('agendada','realizada','cancelada','falta') NOT NULL DEFAULT 'agendada',
	`notes` text,
	`rating` int,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `lessons_id` PRIMARY KEY(`id`)
);

ALTER TABLE `students` MODIFY COLUMN `status` enum('ativo','inativo','pausado') NOT NULL DEFAULT 'ativo';
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `instrumentId` int;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `level` enum('iniciante','intermediario','avancado') DEFAULT 'iniciante' NOT NULL;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `monthlyFee` decimal(10,2) DEFAULT '0.00' NOT NULL;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `startDate` date;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `notes` text;

ALTER TABLE `monthly_stats` ADD COLUMN IF NOT EXISTS `lessonsGiven` int DEFAULT 0 NOT NULL;
ALTER TABLE `monthly_stats` ADD COLUMN IF NOT EXISTS `lessonsCancelled` int DEFAULT 0 NOT NULL;

